(window.webpackJsonp=window.webpackJsonp||[]).push([[14],{526:function(e,o,t){"use strict";t.r(o);var i=t(3),s=Object(i.a)({},(function(){var e=this,o=e.$createElement,t=e._self._c||o;return t("ContentSlotsDistributor",{attrs:{"slot-key":e.$parent.slotKey}},[t("blockquote",[t("p",[e._v("UML建模工具相信大家有所了解，那么你对UML建模工具Visio 、Rational Rose、PowerDesign之间的区别和联系是否了解，这里就像大家简单介绍一下。\nUML建模工具Visio 、Rational Rose、PowerDesign的比较")])]),e._v(" "),t("p",[e._v("ROSE是直接从UML发展而诞生的设计工具，它的出现就是为了对UML建模的支持，ROSE一开始没有对数据库端建模的支持，但是在现在的版本中已经加入数据库建模的功能。ROSE主要是在开发过程中的各种语义、模块、对象以及流程，状态等描述比较好，主要体现在能够从各个方面和角度来分析和设计，使软件的开发蓝图更清晰，内部结构更加明朗（但是它的结构仅仅对那些对掌握UML的开发人员，也就是说对客户了解系统的功能和流程等并不一定很有效），对系统的代码框架生成有很好的支持。但对数据库的开发管理和数据库端的迭代不是很好。")]),e._v(" "),t("p",[e._v("PowerDesigner原来是对数据库建模而发展起来的一种数据库建模工具。直到7.0版才开始对面向对象的开发的支持，后来又引入了对UML的支持。但是由于PowerDesigner侧重不一样，所以它对数据库建模的支持很好，支持了能够看到的90%左右的数据库，对UML的建模使用到的各种图的支持比较滞后。但是在最近得到加强。所以使用它来进行UML开发的并不多，很多人都是用它来作为数据库的建模。如果使用UML分析，它的优点是生成代码时对Sybase的产品PowerBuilder的支持很好（其它UML建模工具则没有或者需要一定的插件），其他面向对象语言如 C++，Java，VB,C#等支持也不错。但是它好像继承了Sybase公司的一贯传统，对中国的市场不是很看看好，所以对中文的支持总是有这样或那样的问题。")]),e._v(" "),t("p",[e._v("UML建模工具Visio 原来仅仅是一种画图工具，能够用来描述各种图形（从电路图到房屋结构图），也是到VISIO2000才开始引进软件分析设计功能到代码生成的全部功能，它可以说是目前最能够用图形方式来表达各种商业图形用途的工具（对软\n件开发中的UML支持仅仅是其中很少的一部分）。它跟微软的office产品的能够很好兼容。能够把图形直接复制或者内嵌到WORD的文档中。但是对于代码的生成更多是支持微软的产品如VB,VC++,MS SQL Server 等（这也是微软的传统），所以它可以说用于图形语义的描述比较方便，但是用于软件开发过程的迭代开发则有点牵强。")]),e._v(" "),t("p",[e._v("UML建模工具Visio 、Rational Rose、PowerDesign三种建模工具应用最广：\n1. Rational Rose，它是ibm的 。\n2.Microsoft的 Microsoft Office Visio® 2003\n3.Enterprise Architect。还有其他工具如PowerDesigner等")]),e._v(" "),t("p",[e._v("1.Rational Rose是一种基于UML的建模工具。在面向对象应用程序开发领域，Rational Rose是影响其发展的一个重要因素。Rational Rose自推出以来就受到了业界的瞩目，并一直引领着可视化建模工具的发展。越来越多的软件公司和开发团队开始或者已经采用Rational Rose，用于大型项目开发的分析、建模与设计等方面。\n从使用的角度分析，Rational Rose易于使用，支持使用多种构件和多种语言的复杂系统建模；利用双向工程技术可以实现迭代式开发；团队管理特性支持大型、复杂的项目和大型而且通常队员分散在各个不同地方的开发团队。同时，Rational Rose与微软Visual Studio系列工具中GUI的完美结合所带来的方便性，使得它成为绝大多数开发人员首选建模工具；Rose还是市场上第一个提供对基于UML的数据建模和Web建模支持的工具。此外，Rose还为其他一些领域提供支持，如用户定制和产品性能改进。\n具体介绍可参看http://www.uml.org.cn/RequirementProject/200604043.htm")]),e._v(" "),t("p",[e._v("2.UML建模工具Visio ® 2003的简介请看\nhttp://www.uml.org.cn/UMLTools/psf/Guide.doc\nhttp://www.microsoft.com/china/office/xp/visio/default.asp")]),e._v(" "),t("p",[e._v("3.Enterprise Architect\nEnterprise Architect是一个全功能的、基于UML的visual CASE工具，主要用于设计、编写、构建并管理以目标为导向的软件系统。它支持用户案例、商务流程模式以及动态的图表、分类、界面、协作、结构以及物理模型。此外，它还支持C++、Java、Visual Basic、Delphi、C#以及VB.Net。具体可看http://www.softwarechn.com/SparxSystems/sparxsystems_index.htm")]),e._v(" "),t("p",[e._v("4.PowerDesigner工具简介请看\nhttp://www.uml.org.cn/UMLTools/powerDesigner/powerDesignerToolIntroduction.htm")]),e._v(" "),t("p",[e._v("5.EA与Rose UML建模工具比较\nhttp://51cmm.csai.cn/casepanel/ST/No061.htm")]),e._v(" "),t("p",[e._v("6.uml介绍请看uml中国官方网站，这里有很多关于uml建模和建模工具的介绍\nhttp://www.uml.org.cn")]),e._v(" "),t("p",[e._v("原文：http://developer.51cto.com/art/201006/207993.htm")])])}),[],!1,null,null,null);o.default=s.exports}}]);